#define LOG_MEM_BANKS 5
#define OFFSET(n) ((n) >> LOG_MEM_BANKS)


template<typename T, int N>
void scan_bcao (
  const int64_t nblocks,
        T *__restrict__ g_odata,
  const T *__restrict__ g_idata,
  int grid_size)
{
  #pragma omp target
  {
    #pragma omp teams num_teams(grid_size) thread_limit(N/2)
    {
      T temp[2*N];

      int team_num = omp_get_team_num(1);
      int thid = omp_get_thread_num();

      for (int64_t bid = team_num; bid < nblocks; bid += grid_size)
      {
        auto gi = g_idata + bid * N;
        auto go = g_odata + bid * N;

        int a = thid;
        int b = a + (N/2);
        int oa = OFFSET(a);
        int ob = OFFSET(b);

        temp[a + oa] = gi[a];
        temp[b + ob] = gi[b];

        int offset = 1;
        for (int d = N >> 1; d > 0; d >>= 1)
        {
          #pragma omp barrier
          if (thid < d)
          {
            int ai = offset*(2*thid+1)-1;
            int bi = offset*(2*thid+2)-1;
            ai += OFFSET(ai);
            bi += OFFSET(bi);
            temp[bi] += temp[ai];
          }
          offset *= 2;
        }

        if (thid == 0) temp[N-1+OFFSET(N-1)] = 0; 
        for (int d = 1; d < N; d *= 2) 
        {
          offset >>= 1;
          #pragma omp barrier
          if (thid < d)
          {
            int ai = offset*(2*thid+1)-1;
            int bi = offset*(2*thid+2)-1;
            ai += OFFSET(ai);
            bi += OFFSET(bi);
            T t = temp[ai];
            temp[ai] = temp[bi];
            temp[bi] += t;
          }
        }
        #pragma omp barrier 

        go[a] = temp[a + oa];
        go[b] = temp[b + ob];
      }
    }
  }
}

template<typename T, int N>
void scan(
  const int64_t nblocks,
        T *__restrict__ g_odata,
  const T *__restrict__ g_idata,
  int grid_size)
{
  #pragma omp target
  {
    #pragma omp teams num_teams(grid_size) thread_limit(N/2)
    {
      T temp[N];

      int team_num = omp_get_team_num(1);
      int thid = omp_get_thread_num();

      for (int64_t bid = team_num; bid < nblocks; bid += grid_size)
      {
        auto gi = g_idata + bid * N;
        auto go = g_odata + bid * N;

        int offset = 1;
        temp[2*thid]   = gi[2*thid];
        temp[2*thid+1] = gi[2*thid+1];
        for (int d = N >> 1; d > 0; d >>= 1)
        {
          #pragma omp barrier
          if (thid < d)
          {
            int ai = offset*(2*thid+1)-1;
            int bi = offset*(2*thid+2)-1;
            temp[bi] += temp[ai];
          }
          offset *= 2;
        }

        if (thid == 0) temp[N-1] = 0; 
        for (int d = 1; d < N; d *= 2) 
        {
          offset >>= 1;
          #pragma omp barrier
          if (thid < d)
          {
            int ai = offset*(2*thid+1)-1;
            int bi = offset*(2*thid+2)-1;
            T t = temp[ai];
            temp[ai] = temp[bi];
            temp[bi] += t;
          }
