#define RADIUS 7
#define BLOCK_SIZE 256

#pragma omp declare target
void stencil_1d(const int *__restrict__ in, int *__restrict__ out, int *__restrict__ temp_global)
{
  int team = omp_get_team_num();
  int tid = omp_get_thread_num();
  int nthreads = omp_get_num_threads();
  int gindex = tid + team * nthreads;
  int lindex = tid + RADIUS;

  int *temp = temp_global + team * (BLOCK_SIZE + 2 * RADIUS);

  temp[lindex] = in[gindex];

  if (tid < RADIUS) {
    temp[lindex - RADIUS] = (gindex < RADIUS) ? 0 : in[gindex - RADIUS];
    temp[lindex + BLOCK_SIZE] = in[gindex + BLOCK_SIZE];
  }

  #pragma omp barrier

  int result = 0;
  for (int offset = -RADIUS ; offset <= RADIUS ; offset++)
    result += temp[lindex + offset];

  out[gindex] = result; 
}

int main(int argc, char* argv[]) {
  if (argc != 3) {
    printf("Usage: %s <length> <repeat>\n", argv[0]);
    printf("length is a multiple of %d\n", BLOCK_SIZE);
    return 1;
  }
  const int length = atoi(argv[1]);
  const int repeat = atoi(argv[2]);

  int size = length * sizeof(int);
  int pad_size = (length + RADIUS) * sizeof(int);

  int *a, *b;

  a = (int *)malloc(pad_size); 
  b = (int *)malloc(size);

  for (int i = 0; i < length+RADIUS; i++) a[i] = i;

  int dev = omp_get_default_device();
  int host_dev = omp_get_initial_device();

  int *d_a, *d_b, *d_temp;

  d_a = (int *)omp_target_alloc(pad_size, dev);
  d_b = (int *)omp_target_alloc(size, dev);

  int num_blocks = length / BLOCK_SIZE;
  int temp_elements = num_blocks * (BLOCK_SIZE + 2 * RADIUS);
  d_temp = (int *)omp_target_alloc(temp_elements * sizeof(int), dev);

  omp_target_memcpy(d_a, a, pad_size, dev, host_dev);

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; i < repeat; i++) {
    #pragma omp target teams distribute parallel for num_teams(num_blocks) thread_limit(BLOCK_SIZE)
    for (int j = 0; j < length; j++) {
      stencil_1d(d_a, d_b, d_temp);
    }
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  printf("Average kernel execution time: %f (s)\n", (time * 1e-9f) / repeat);

  omp_target_memcpy(b, d_b, size, host_dev, dev);

  bool ok = true;
  for (int i = 0; i < 2*RADIUS; i++) {
    int s = 0;
    for (int j = i; j <= i+2*RADIUS; j++)
      s += j < RADIUS ? 0 : (a[j] - RADIUS);
    if (s != b[i]) {
      printf("Error at %d: %d (host) != %d (device)\n", i, s, b[i]);
      ok = false;
      break;
    }
  }

  for (int i = 2*RADIUS; i < length; i++) {
    int s = 0;
    for (int j = i-RADIUS; j <= i+RADIUS; j++)
      s += a[j];
    if (s != b[i]) {
      printf("Error at %d: %d (host) != %d (device)\n", i, s, b[i]);
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");

  free(a);
  free(b); 
  omp_target_free(d_a, dev); 
  omp_target_free(d_b, dev); 
  omp_target_free(d_temp, dev); 
  return 0;
}

