#include <omp.h>

#define N 2048

#define IDX(i, j) ((i) + (j) * N)

void initialize_data(float* f) {
  for (int j = 0; j < N; ++j) {
    for (int i = 0; i < N; ++i) {
      if (i == 0 || i == N-1) {
        f[IDX(i,j)] = sinf(j * 2 * M_PI / (N - 1));
      }
      else if (j == 0 || j == N-1) {
        f[IDX(i,j)] = sinf(i * 2 * M_PI / (N - 1));
      }
      else {
        f[IDX(i,j)] = 0.0f;
      }
    }
  }
}

void jacobi_step(float* f, const float* f_old, float* error) {
  #pragma omp target parallel
  {
    float f_old_tile[18][18];

    int i = omp_get_thread_num() % N;
    int j = omp_get_thread_num() / N;

    int local_i = i % 16;
    int local_j = j % 16;

    f_old_tile[local_j+1][local_i+1] = f_old[IDX(i,j)];

    if (local_i == 0 && i >= 1) {
      f_old_tile[local_j+1][local_i+0] = f_old[IDX(i-1,j)];
    }
    if (local_i == 15 && i <= N-2) {
      f_old_tile[local_j+1][local_i+2] = f_old[IDX(i+1,j)];
    }
    if (local_j == 0 && j >= 1) {
      f_old_tile[local_j+0][local_i+1] = f_old[IDX(i,j-1)];
    }
    if (local_j == 15 && j <= N-2) {
      f_old_tile[local_j+2][local_i+1] = f_old[IDX(i,j+1)];
    }

    #pragma omp target barrier

    float err = 0.0f;

    if (j >= 1 && j <= N-2) {
      if (i >= 1 && i <= N-2) {
        f[IDX(i,j)] = 0.25f * (f_old_tile[local_j+1][local_i+2] + 
                               f_old_tile[local_j+1][local_i+0] + 
                               f_old_tile[local_j+2][local_i+1] + 
                               f_old_tile[local_j+0][local_i+1]);
        float df = f[IDX(i,j)] - f_old_tile[local_j+1][local_i+1];
        err = df * df;
      }
    }

    float reduction_array[16];
    #pragma omp target atomic write
    reduction_array[local_j] = err;

    #pragma omp target barrier

    if (local_j == 0) {
      err = reduction_array[local_i];
      #pragma omp target atomic read
      for (int k = 0; k < 16; k++) {
        if (k != local_i) {
          float tmp;
          #pragma omp target atomic read
          tmp = reduction_array[k];
          err += tmp;
        }
      }
      #pragma omp target atomic
      *error += err;
    }
  }
}

