template<typename T>
void conv1d_tiled(const T *in,
                  T *out,
                  const int input_width,
                  const int mask_width,
                  const T *mask,
                  int block_size)
{
  int num_blocks = input_width / block_size;
  int n = mask_width / 2;

  #pragma omp target
  {
    #pragma omp teams distribute parallel for
    for (int block = 0; block < num_blocks; block++) {
      T tile[block_size + mask_width - 1];

      int block_start = block * block_size;

      for (int t = 0; t < block_size; t++) {
        int i = block_start + t;
        if (i < input_width) {
          tile[n + t] = in[i];
        }
      }

      for (int t = block_size - n; t < block_size; t++) {
        int halo_left = (block - 1) * block_size + t;
        tile[t - (block_size - n)] = halo_left < 0 ? 0 : in[halo_left];
      }

      for (int t = 0; t < n; t++) {
        int halo_right = (block + 1) * block_size + t;
        tile[t + block_size + n] = halo_right >= input_width ? 0 : in[halo_right];
      }

      #pragma omp barrier

      for (int t = 0; t < block_size; t++) {
        int i = block_start + t;
        if (i < input_width) {
          T s = 0;
          for (int j = 0; j < mask_width; j++) {
            s += tile[t + j] * mask[j];
          }
          out[i] = s;
        }
      }
    }
  }
}

template<typename T>
void conv1d_tiled_caching(const T *in,
                          T *out,
                          const int input_width,
                          const int mask_width,
                          const T *mask,
                          int block_size)
{
  int num_blocks = input_width / block_size;

  #pragma omp target
  {
