    for (int block = 0; block < num_blocks; block++) {
      T tile[block_size];

      int block_start = block * block_size;
      int next_tile_start = (block + 1) * block_size;

      for (int t = 0; t < block_size; t++) {
        int i = block_start + t;
        if (i < input_width) {
          tile[t] = in[i];
        }
      }

      #pragma omp barrier

      for (int t = 0; t < block_size; t++) {
        int i = block_start + t;
        if (i < input_width) {
          int start = i - (mask_width / 2);
          T s = 0;
          for (int j = 0; j < mask_width; j++) {
            int in_index = start + j;
            if (in_index >= 0 && in_index < input_width) {
              if (in_index >= block_start && in_index < next_tile_start) {
                s += tile[t + j - (mask_width / 2)] * mask[j];
              } else {
                s += in[in_index] * mask[j];
              }
            }
          }
          out[i] = s;
        }
      }
    }
  }
}

