template <typename T>
void conv1D(const int input_width, const int mask_width, const int repeat)
{
  size_t size_bytes = input_width * sizeof(T);

  T *a, *b;
  a = (T *)malloc(size_bytes);
  b = (T *)malloc(size_bytes);

  T h_mask[MAX_MASK_WIDTH];

  for (int i = 0; i < MAX_MASK_WIDTH; i++) h_mask[i] = 1;

  srand(123);
  for (int i = 0; i < input_width; i++) {
    a[i] = rand() % 256;
  }

  T *d_a, *d_b, *d_mask;
  d_a = (T *)omp_target_alloc(size_bytes, omp_get_default_device());
  d_b = (T *)omp_target_alloc(size_bytes, omp_get_default_device());
  d_mask = (T *)omp_target_alloc(mask_width * sizeof(T), omp_get_default_device());

  #pragma omp target copyin(a[0:input_width])
  {
    for (int i = 0; i < input_width; i++) {
      d_a[i] = a[i];
    }
  }

  #pragma omp target copyin(h_mask[0:mask_width])
  {
    for (int i = 0; i < mask_width; i++) {
      d_mask[i] = h_mask[i];
    }
  }

  #pragma omp target synchronize

  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d(d_a, d_b, input_width, mask_width, d_mask);
    }
    #pragma omp target synchronize
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    #pragma omp target copyout(b[0:input_width])
    {
      for (int i = 0; i < input_width; i++) {
        b[i] = d_b[i];
      }
    }
    reference(a, b, h_mask, input_width, mask_width);
  }

  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d_tiled(d_a, d_b, input_width, mask_width, d_mask, bs);
    }
    #pragma omp target synchronize
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    #pragma omp target copyout(b[0:input_width])
    {
      for (int i = 0; i < input_width; i++) {
        b[i] = d_b[i];
      }
    }
    reference(a, b, h_mask, input_width, mask_width);
  }

  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d_tiled_caching(d_a, d_b, input_width, mask_width, d_mask, bs);
    }
    #pragma omp target synchronize
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled-caching kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    #pragma omp target copyout(b[0:input_width])
    {
      for (int i = 0; i < input_width; i++) {
        b[i] = d_b[i];
      }
    }
    reference(a, b, h_mask, input_width, mask_width);
  }

  free(a);
  free(b);
  omp_target_free(d_a, omp_get_default_device());
  omp_target_free(d_b, omp_get_default_device());
  omp_target_free(d_mask, omp_get_default_device());
}

